const handle = (($json.body && $json.body.handle) || '').trim();
if (!handle) throw new Error('handle is required');
if (!/^[a-zA-Z0-9_-]{2,60}$/.test(handle)) throw new Error('Invalid handle format');
return [{ json: { handle: handle } }];

const handle = $('Validate Handle').first().json.handle;
const status = ($input.first().json || {}).statusCode;
return [{ json: { handle: handle, exists: status === 200, status_code: status } }];

const body = $json.body || {};
const handle = (body.handle || '').trim();
const code = String(body.code || '').trim();
const userId = (body.user_id || '').trim();
if (!handle) throw new Error('handle is required');
if (!code) throw new Error('code is required');
if (!userId) throw new Error('user_id is required');
if (!/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(userId)) throw new Error('user_id must be a valid UUID');
return [{ json: { handle: handle, code: code, user_id: userId } }];

const prev = $('Validate Confirm Input').first().json;
const handle = prev.handle;
const code = prev.code;
const userId = prev.user_id;
const resp = $input.first().json || {};
const statusCode = resp.statusCode;
const htmlBody = resp.data || resp.body || '';
if (statusCode !== 200) {
  return [{ json: { verified: false, reason: 'RSI profile not found', handle: handle, sql: 'SELECT 1' } }];
}
var verified = htmlBody.indexOf(code) !== -1;
function esc(s) { return String(s).replace(/'/g, "''"); }
var sql = verified
  ? "UPDATE users SET sc_handle='" + esc(handle) + "', sc_verified=true, sc_verified_at=NOW() WHERE user_id='" + esc(userId) + "'::uuid RETURNING user_id, sc_handle, sc_verified"
  : 'SELECT 1';
return [{ json: { verified: verified, handle: handle, user_id: userId, sql: sql, reason: verified ? null : 'Code not found in RSI bio' } }];
